/** Tiny neutral blur placeholder for local textile images */
export const TEXTILE_BLUR =
  "data:image/jpeg;base64,";

export function productImageAlt(name: string, category: string, index = 0): string {
  const views = ["front view", "detail texture", "alternate angle", "close-up weave"];
  const view = views[index] ?? `view ${index + 1}`;
  return `${name} — ${category} premium African textile, ${view}`;
}